using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class EhrServiceTests_GetEhrDocument_WithRequesterId_FakeEhr_ShouldReturnNotFound : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "EhrService"    };    [SkippableFact]    public async Task GetEhrDocument_WithRequesterId_FakeEhr_ShouldReturnNotFound()    {    await AuthenticateAsAdminAsync(EhrClient);    EhrClient.DefaultRequestHeaders.Add("X-Requester-Id", TestSeedData.DoctorUserId.ToString());    var response = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.GetDocument(Guid.NewGuid()));        Assert.True(response.StatusCode == HttpStatusCode.NotFound || response.StatusCode == HttpStatusCode.Forbidden);    EhrClient.DefaultRequestHeaders.Remove("X-Requester-Id");    }}
